using System.Collections.Generic;using UnityEngine;public class SdvSceneAutoBinder : MonoBehaviour{    [Header("General")]    public bool bindOnStart = true;    public bool verboseLog = true;    public UdpUiRenderReceiver receiver;    [Header("External Scene Names")]    public string roadLaneName = "RoadLane";    public string flowStripName = "FlowStrip";    public string vehicleMarkerName = "VehicleMarker";    public string emergencyLeftName = "EmergencyLightLeft";    public string emergencyRightName = "EmergencyLightRight";    [Header("Cabin Scene Names")]    public string[] ambientZoneNames = { "AmbientZone_Driver", "AmbientZone_Passenger", "AmbientZone_Rear" };    public string flowPhasePrefix = "FlowPhase_";    public int flowPhaseCount = 8;    public string leftArrowName = "DirectionArrow_Left";    public string rightArrowName = "DirectionArrow_Right";    public string rearArrowName = "DirectionArrow_Rear";    private void Start()    {        if (bindOnStart)        {            BindAll();        }    }    [ContextMenu("Bind All")]    public void BindAll()    {        if (receiver == null)        {            receiver = FindObjectOfType<UdpUiRenderReceiver>();        }        if (receiver == null)        {            Log("UdpUiRenderReceiver not found.");            return;        }        BindExternalController();        BindCabinController();    }    private void BindExternalController()    {        ExternalRoadViewController ext = FindObjectOfType<ExternalRoadViewController>();        if (ext == null)        {            Log("ExternalRoadViewController not found. Skipped.");            return;        }        ext.receiver = receiver;        ext.roadLaneRenderer = FindRendererByName(roadLaneName);        ext.flowStripRenderer = FindRendererByName(flowStripName);        ext.vehicleMarker = FindTransformByName(vehicleMarkerName);        ext.emergencyLeftRenderer = FindRendererByName(emergencyLeftName);        ext.emergencyRightRenderer = FindRendererByName(emergencyRightName);        Log("ExternalRoadViewController bound.");    }    private void BindCabinController()    {        CabinPanoramaViewController cabin = FindObjectOfType<CabinPanoramaViewController>();        if (cabin == null)        {            Log("CabinPanoramaViewController not found. Skipped.");            return;        }        cabin.receiver = receiver;        var ambientRenderers = new List<Renderer>();        foreach (string n in ambientZoneNames)        {            Renderer r = FindRendererByName(n);            if (r != null)            {                ambientRenderers.Add(r);            }        }        cabin.ambientZoneRenderers = ambientRenderers.ToArray();        var phaseObjects = new List<GameObject>();        for (int i = 0; i < flowPhaseCount; i++)        {            GameObject go = GameObject.Find(flowPhasePrefix + i);            if (go != null)            {                phaseObjects.Add(go);            }        }        cabin.flowPhaseIndicators = phaseObjects.ToArray();        cabin.leftArrow = FindGameObjectByName(leftArrowName);        cabin.rightArrow = FindGameObjectByName(rightArrowName);        cabin.rearArrow = FindGameObjectByName(rearArrowName);        Log("CabinPanoramaViewController bound.");    }    private static Renderer FindRendererByName(string objectName)    {        GameObject go = FindGameObjectByName(objectName);        if (go == null)        {            return null;        }        return go.GetComponent<Renderer>();    }    private static Transform FindTransformByName(string objectName)    {        GameObject go = FindGameObjectByName(objectName);        return go == null ? null : go.transform;    }    private static GameObject FindGameObjectByName(string objectName)    {        if (string.IsNullOrEmpty(objectName))        {            return null;        }        return GameObject.Find(objectName);    }    private void Log(string message)    {        if (verboseLog)        {            Debug.Log("[SdvSceneAutoBinder] " + message);        }    }}